import{_ as s,o as p,c as i,a2 as t}from"./chunks/framework.M-AdQQii.js";const c=JSON.parse('{"title":"1.2 跑商","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 跑商根据交通方式的不同，可以分为以下两种： ①跑陆商②跑海商 根据货物的不同，可以分为以下两种： ③跑普通货④跑星星货⑤跑住民货⑥跑商团货 ⑦跑债券货⑧跑发酵货⑨跑黑炭⑩跑龙骨 ③④⑤⑥⑦","frontmatter":{"title":"1.2 跑商","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 跑商根据交通方式的不同，可以分为以下两种： ①跑陆商②跑海商 根据货物的不同，可以分为以下两种： ③跑普通货④跑星星货⑤跑住民货⑥跑商团货 ⑦跑债券货⑧跑发酵货⑨跑黑炭⑩跑龙骨 ③④⑤⑥⑦","outline":"deep"},"headers":[],"relativePath":"life/1-2.md","filePath":"life/1-2.md","lastUpdated":null}'),u={name:"life/1-2.md"};function g(e,a,l,r,o,f){return p(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="_1-2-跑商" tabindex="-1">1.2 跑商 <a id="s016-068ca127"></a> <a class="header-anchor" href="#_1-2-跑商" aria-label="Permalink to &quot;1.2 跑商 &lt;a id=&quot;s016-068ca127&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_1-2-1-跑商的种类" tabindex="-1">1.2.1 跑商的种类 <a id="s017-87bcb425"></a> <a class="header-anchor" href="#_1-2-1-跑商的种类" aria-label="Permalink to &quot;1.2.1 跑商的种类 &lt;a id=&quot;s017-87bcb425&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>跑商根据交通方式的不同，可以分为以下两种：</p><p>①跑陆商②跑海商</p><p>根据货物的不同，可以分为以下两种：</p><p>③跑普通货④跑星星货⑤跑住民货⑥跑商团货</p><p>⑦跑债券货⑧跑发酵货⑨跑黑炭⑩跑龙骨</p><p>③④⑤⑥⑦⑧在跑完8 小时后，收益的金币将会通过邮件发放。</p><p>⑨⑩在跑完8 小时后，收益的资源将会通过邮件发放。</p><h2 id="_1-2-2-跑商的前置准备" tabindex="-1">1.2.2 跑商的前置准备 <a id="s018-fd0bf315"></a> <a class="header-anchor" href="#_1-2-2-跑商的前置准备" aria-label="Permalink to &quot;1.2.2 跑商的前置准备 &lt;a id=&quot;s018-fd0bf315&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>注意事项！！！</p><p>在无加成的熟练度未满23W 之前，不推荐跑海商，也不推荐跑④和⑦。</p><p>跑商前我们需要将称号、装备和时装更换为加跑商熟练度的称号、装备和时装。</p><p>所需要的操作如图所示：</p><p>首先你要按下shift+y 键唤出里程碑，</p><p>然后右键箭头指向的方框位置：</p><p>操作如图：</p><p>然后鼠标左键框框①处，再左键箭头②处，即可切换称号。</p><p>然后你需要在做货前穿上图示时装和装备：</p><p>如果是你是准备①跑陆商，需要准备一个拖拉机，最好再装备一个拖拉机时装：</p><p>如果是②跑海商，我们需要准备一艘贸易船。如图所示：</p><p>贸易船跑交易品建议至少两个船帆都达到圣物级别。</p><p>如果你是准备吊船，那么你还至少需要准备一个圣物级别的鱼叉，如图所示：</p><p>如果你是要敲发酵或者要去光芒跑黑炭的话，建议你准备2 个坐骑，分别是：</p><p>它们能给你提供背货时的移速加成，分别是：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_607.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_608.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_613.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_614.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_615.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_616.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_621.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_622.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_627.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_628.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_629.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_630.jpeg" alt="图示：1.2.2 跑商的前置准备" loading="lazy"></figure><h2 id="_1-2-3-跑商对于时间的要求" tabindex="-1">1.2.3 跑商对于时间的要求 <a id="s019-521227ca"></a> <a class="header-anchor" href="#_1-2-3-跑商对于时间的要求" aria-label="Permalink to &quot;1.2.3 跑商对于时间的要求 &lt;a id=&quot;s019-521227ca&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>所有的货物在制作出来或者购买出来时都会有一个时间，将鼠标移动在货物上即可查看（不同货物过期时间不一样）。如图所示：</p><p>因此当最佳时间结束之后，我们跑商的收益就会受损，所以我们需要根据实际情况来判断我们能不能在过期前跑完这些货物。</p><p>如果是发酵货物，那么货物还需要一个发酵时间，在发酵时间到达之前贩卖货物</p><p>的话一样会损失收益。如图：</p><p>蓝颜商会运输品（债券货）比较特殊，没有过期时间，你什么时间做都可以，但是放在地上依然存在消失时间。</p><p>现实时间推荐：</p><p>下午可以跑海</p><p>全天候可以跑安全区</p><p>任何时间只要出安全区就有可能被打劫（内战时期尤甚）</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_636.jpeg" alt="图示：1.2.3 跑商对于时间的要求" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_643.jpeg" alt="图示：1.2.3 跑商对于时间的要求" loading="lazy"></figure><h2 id="_1-2-4-怎么跑陆商" tabindex="-1">1.2.4 怎么跑陆商 <a id="s020-add0e5d8"></a> <a class="header-anchor" href="#_1-2-4-怎么跑陆商" aria-label="Permalink to &quot;1.2.4 怎么跑陆商 &lt;a id=&quot;s020-add0e5d8&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>参考笔者B 站视频：BV1CJ8deaEQe</p><p>注意事项：一定要锁车！！！不然别怪敌对势力用奶牛之类的炸你，然后抢走你的拖拉机。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_649.jpeg" alt="图示：1.2.4 怎么跑陆商" loading="lazy"></figure><h2 id="_1-2-5-怎么跑海商" tabindex="-1">1.2.5 怎么跑海商 <a id="s021-28619033"></a> <a class="header-anchor" href="#_1-2-5-怎么跑海商" aria-label="Permalink to &quot;1.2.5 怎么跑海商 &lt;a id=&quot;s021-28619033&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>内战结束后更新。</p><h2 id="_1-2-6-打劫与被打劫" tabindex="-1">1.2.6 打劫与被打劫 <a id="s022-ac786398"></a> <a class="header-anchor" href="#_1-2-6-打劫与被打劫" aria-label="Permalink to &quot;1.2.6 打劫与被打劫 &lt;a id=&quot;s022-ac786398&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="打劫的情况" tabindex="-1">打劫的情况： <a id="s023-7373da34"></a> <a class="header-anchor" href="#打劫的情况" aria-label="Permalink to &quot;打劫的情况： &lt;a id=&quot;s023-7373da34&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>如果你或者国人发现敌对势力玩家正在进行非安全区的跑商活动，可以通过语音（KOOK）或者打字的方式提醒并邀请其他国人玩家参与打劫。</p><h3 id="被打劫的情况" tabindex="-1">被打劫的情况： <a id="s024-14a8a436"></a> <a class="header-anchor" href="#被打劫的情况" aria-label="Permalink to &quot;被打劫的情况： &lt;a id=&quot;s024-14a8a436&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>如果你想要进行非安全区的跑商行为，那么笔者强烈推荐你在跑商开始前就挂在语音频道上，这样子你一出事就可以立马组团、报点、报对面职业和人数已经打劫方式。同时还能告知救援人员你的情况，这样子做足了这些准备，才能最大程度保证救援人员可以帮你抢回你的货物。</p><p>但是有时候对面人数过多，如果你的船被开出了安全区，这种情况下也是抢不回来你的货物的，这种情况就认了吧。</p><p>还有一个注意事项！！！</p><p>那就是跑商一定要锁船、锁车。如果救援玩家听到你因为没有锁船锁车而被抢劫（尤其是在安全区），那么救援玩家的救援积极性将会大大下降。</p><p>最后还要提一点：</p><p>其他玩家能来救你是情分，不是本分。不管能不能抢回来你的货物，你都应该感谢他们而非指责他们救援不到位或者不及时。</p><p>你可以通过语音或者打字来表达你的谢意。相信我，其他玩家更愿意去救嘴甜的、</p><p>人缘好的人，而不是嘴臭、人缘差的人。</p><h2 id="_1-2-7-各种类跑商的优缺点" tabindex="-1">1.2.7 各种类跑商的优缺点 <a id="s025-c0482daa"></a> <a class="header-anchor" href="#_1-2-7-各种类跑商的优缺点" aria-label="Permalink to &quot;1.2.7 各种类跑商的优缺点 &lt;a id=&quot;s025-c0482daa&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="普通货" tabindex="-1">普通货： <a id="s026-6d0f498d"></a> <a class="header-anchor" href="#普通货" aria-label="Permalink to &quot;普通货： &lt;a id=&quot;s026-6d0f498d&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>制作材料和需要劳动力较少，但是可获得金币较少。如图所示</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_662.jpeg" alt="图示：普通货：" loading="lazy"></figure><h3 id="星星货" tabindex="-1">星星货： <a id="s027-c3c0667e"></a> <a class="header-anchor" href="#星星货" aria-label="Permalink to &quot;星星货： &lt;a id=&quot;s027-c3c0667e&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>制作材料和需要劳动力较多，并且制作材料需要使用德妃纳之星，但是星星货可</p><p>获得金币较多。如图所示：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_663.jpeg" alt="图示：星星货：" loading="lazy"></figure><h3 id="住民货" tabindex="-1">住民货： <a id="s028-1236a7e9"></a> <a class="header-anchor" href="#住民货" aria-label="Permalink to &quot;住民货： &lt;a id=&quot;s028-1236a7e9&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>住民货分两种：</p><p>1）自己做的</p><p>2）住民制作台旁边的“垃圾”，如图所示：</p><p>俗称的捡垃圾便是让你去住民会馆附近拾取住民货物去跑，虽然可能货物可能已经过了最近贩卖时间，但是由于制作人熟练度通常较高，而且无须自己使用材料和劳动力制作，所以对于新人来说收益还不错。</p><p>住民货物由于大量垃圾存在，所以货率通常不高。住民货物在高货率下可以获得的金币比普通货要多。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_671.jpeg" alt="图示：住民货：" loading="lazy"></figure><h3 id="肥料货" tabindex="-1">肥料货： <a id="s029-f37b70f5"></a> <a class="header-anchor" href="#肥料货" aria-label="Permalink to &quot;肥料货： &lt;a id=&quot;s029-f37b70f5&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>肥料货物最大的特点就是制作材料统一，如图所示：</p><p>肥料货物可以在商团房子的制作台上制作，你可以选择去公开的商团房子，或者去家族的/工会的商团房子上制作肥料货物。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_677.jpeg" alt="图示：肥料货：" loading="lazy"></figure><h3 id="债券货" tabindex="-1">债券货： <a id="s030-5d0bc7e4"></a> <a class="header-anchor" href="#债券货" aria-label="Permalink to &quot;债券货： &lt;a id=&quot;s030-5d0bc7e4&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>债券货的制作材料也是统一的，如图所示：</p><p>债券货可以卖很多的金，但是也很吃劳动力，建议在货率120%左右再跑。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_678.jpeg" alt="图示：债券货：" loading="lazy"></figure><h3 id="发酵货" tabindex="-1">发酵货： <a id="s031-81bc56ed"></a> <a class="header-anchor" href="#发酵货" aria-label="Permalink to &quot;发酵货： &lt;a id=&quot;s031-81bc56ed&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>发酵货分2 种，大陆发酵和原大陆发酵（不推荐），制作材料一样，成品不是一个东西，不通用。发酵架有如下三种：</p><p>蜂蜜最值钱，其次是药材，再其次是奶酪。发酵货优点是价格高，可以刷新货率，</p><p>只要交易品没到14J，就可以一直稳定130%货率，建议多次混跑，可以保证每个货最低129%货率。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_685.jpeg" alt="图示：发酵货：" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_686.jpeg" alt="图示：发酵货：" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_687.jpeg" alt="图示：发酵货：" loading="lazy"></figure><h2 id="_1-2-8-跑商货率的查看与变化" tabindex="-1">1.2.8 跑商货率的查看与变化 <a id="s032-c00144a1"></a> <a class="header-anchor" href="#_1-2-8-跑商货率的查看与变化" aria-label="Permalink to &quot;1.2.8 跑商货率的查看与变化 &lt;a id=&quot;s032-c00144a1&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>按下快捷键shift+o 可以唤出如下的贸易面板：</p><p>选择产地和目的地即可查看对应货率，如下：</p><p>滑动滚轮即可查看其他货物的货率。</p><p>如果我们不想看各个地图货物的货率，而是想看交易所里特产的数目的话，我们可以到特产贩卖商人处查看，如下：</p><p>信息面板红框处可以选择查看某一个地图到该交易所的特产数量、货率和基础金额。蓝框处为搜索栏，可以搜索某个地图或者某个类型的特产的信息。</p><p>小技巧，想知道发酵满没满可以先点击交易品商人看看物价是不是70%14 金，</p><p>不是的话放心大胆跑就可以了，是的话就要看交易所里有多少发酵了，在搜索栏里搜索发酵即可。</p><p>接下来是货率变化的内容：</p><p>如图所示，刷新一次交易品需要对应大陆的40 个普通特产、30 个商团特产、20个发酵特产。当交易品物价到达70%即14 金买货时，就不在消耗特产来刷新交易品数量，表现在货率上就是发酵货率越来越低的同时，其他特产货率也没有恢复（因为并没有消耗特产，在交易所里的特产数量一直在增加）</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_697.jpeg" alt="图示：1.2.8 跑商货率的查看与变化" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_698.jpeg" alt="图示：1.2.8 跑商货率的查看与变化" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_704.jpeg" alt="图示：1.2.8 跑商货率的查看与变化" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_705.jpeg" alt="图示：1.2.8 跑商货率的查看与变化" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_710.jpeg" alt="图示：1.2.8 跑商货率的查看与变化" loading="lazy"></figure><h2 id="_1-2-9-公开权限商团房子的位置" tabindex="-1">1.2.9 公开权限商团房子的位置 <a id="s033-5c3ce746"></a> <a class="header-anchor" href="#_1-2-9-公开权限商团房子的位置" aria-label="Permalink to &quot;1.2.9 公开权限商团房子的位置 &lt;a id=&quot;s033-5c3ce746&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>笔者在制作攻略时所知道的公开商团如下图所示：</p><h3 id="西大陆" tabindex="-1">西大陆 <a id="s034-a9f2efad"></a> <a class="header-anchor" href="#西大陆" aria-label="Permalink to &quot;西大陆 &lt;a id=&quot;s034-a9f2efad&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>优质公开商团（格威尔）：</p><p>优质公开商团（黄金）：</p><p>优质公开商团（双冠）：</p><p>公开商团（玛瑞）：</p><p>公开商团（西风）：</p><p>公开商团（地狱）：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_716.jpeg" alt="图示：西大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_717.jpeg" alt="图示：西大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_723.jpeg" alt="图示：西大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_724.jpeg" alt="图示：西大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_729.jpeg" alt="图示：西大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_730.jpeg" alt="图示：西大陆" loading="lazy"></figure><h3 id="东大陆" tabindex="-1">东大陆 <a id="s035-f3ba0e03"></a> <a class="header-anchor" href="#东大陆" aria-label="Permalink to &quot;东大陆 &lt;a id=&quot;s035-f3ba0e03&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>伊尼斯泰尔：</p><p>古代森林：</p><p>咏唱之地：</p><p>猎鹰高原：</p><p>彩虹荒野：</p><p>摩哈特比：</p><p>黎明半岛:</p><p>烈日峡谷：</p><p>洛卡山脉：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_735.jpeg" alt="图示：东大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_736.jpeg" alt="图示：东大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_742.jpeg" alt="图示：东大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_743.jpeg" alt="图示：东大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_748.jpeg" alt="图示：东大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_749.jpeg" alt="图示：东大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_754.jpeg" alt="图示：东大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_755.jpeg" alt="图示：东大陆" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_760.jpeg" alt="图示：东大陆" loading="lazy"></figure><h2 id="_1-2-10-作者公会商团房子位置" tabindex="-1">1.2.10 作者公会商团房子位置 <a id="s036-ee396fd1"></a> <a class="header-anchor" href="#_1-2-10-作者公会商团房子位置" aria-label="Permalink to &quot;1.2.10 作者公会商团房子位置 &lt;a id=&quot;s036-ee396fd1&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>十字星平原入口处（门口坡可以直接下去）：</p><p>索兹里德半岛入海口处（用不用鱼叉都可以跑）：</p><p>公会商团跑商教程参考视频：BV12x4y1t7SB</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_765.jpeg" alt="图示：1.2.10 作者公会商团房子位置" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_766.jpeg" alt="图示：1.2.10 作者公会商团房子位置" loading="lazy"></figure><h2 id="_1-2-11-发酵货的制备和运送" tabindex="-1">1.2.11 发酵货的制备和运送 <a id="s037-484f78e6"></a> <a class="header-anchor" href="#_1-2-11-发酵货的制备和运送" aria-label="Permalink to &quot;1.2.11 发酵货的制备和运送 &lt;a id=&quot;s037-484f78e6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="制备发酵架" tabindex="-1">制备发酵架 <a id="s038-ccdec092"></a> <a class="header-anchor" href="#制备发酵架" aria-label="Permalink to &quot;制备发酵架 &lt;a id=&quot;s038-ccdec092&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>跑发酵需要先做置物架，制作置物架熟练度对收益无影响，因此萌新可以通过帮大佬搓发酵架来获取经商熟练度。</p><p>如果你想要长期跑发酵，那么最好有一片地（自己的或者野外的）来种大量的果树和牛棚，不然发酵消耗材料很多，扫拍卖行材料或者拍卖行发酵架会比较亏。蜂蜜则是推荐便宜时拍卖行多扫点来用，不建议自己弄。</p><h3 id="制备发酵货" tabindex="-1">制备发酵货 <a id="s039-dcb9909b"></a> <a class="header-anchor" href="#制备发酵货" aria-label="Permalink to &quot;制备发酵货 &lt;a id=&quot;s039-dcb9909b&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>发酵的放置方法为右键背包内的置物架，放置在地里，然后走进按F 敲出发酵背在身上。注意：这时候要加速敲的读条虽然是畜牧熟练度和畜牧晨露，但是收益是按这时候你的经商熟练度算的，所以这时候你既要穿晨露腰带也要穿晨露鞋子。当然你也可以吃熟练度卷轴敲半小时发酵，交货再吃一个卷轴，以获取最高价格。（跑商熟练度最高可达35.2W）</p><p>敲好货后摆在地上即可，8X8 地极限摆货为48 个。</p><p>发酵所需时间为23 小时，但是不同地图发酵完成后的新鲜时间不同，黄金、珊瑚、地狱、西风等地图的新鲜时间较长，都为2 天左右。</p><p>发酵货运送分为陆运和海运两种，一般优质的海运发酵地，地皮都会比较贵，前期建议白嫖公会的家族的，有钱了再考虑买发酵地皮。</p><h3 id="原大陆发酵相关" tabindex="-1">原大陆发酵相关 <a id="s040-1b060f02"></a> <a class="header-anchor" href="#原大陆发酵相关" aria-label="Permalink to &quot;原大陆发酵相关 &lt;a id=&quot;s040-1b060f02&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>由于原大陆的发酵货率极烂（50%40%等），原大陆发酵只能在地里放到过期看能不能刷新出超级发酵，超级发酵一个几千金，但是其他过期+腐烂的发酵一个只能卖十几金，连架子钱都回不来。</p><p>而且原大陆全程非安全区，需要跑车送货才比较安全，但是在居住区太里面的话，</p><p>跑车又会被各种东西卡住导致风险变大，所以你想跑原大陆发酵的话，还需要居住区边缘的土地和一辆跑车。</p><h2 id="_1-2-12-西大陆各个交易所的发酵收益" tabindex="-1">1.2.12 西大陆各个交易所的发酵收益 <a id="s041-d1bfcf4d"></a> <a class="header-anchor" href="#_1-2-12-西大陆各个交易所的发酵收益" aria-label="Permalink to &quot;1.2.12 西大陆各个交易所的发酵收益 &lt;a id=&quot;s041-d1bfcf4d&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>索兹里德半岛交易所如下：</p><p>奶酪</p><p>药材</p><p>蜂蜜</p><p>西风脊</p><p>73.85.55</p><p>75.28.21</p><p>77.64.66</p><p>备注：本表基于27.4W 熟练度和130%货率制作，价格随熟练度和货率变动。By：幸运菌</p><p>地狱沼泽</p><p>71.30.92</p><p>73.05.43</p><p>74.49.71</p><p>珊瑚海岸</p><p>71.28.93</p><p>73.03.15</p><p>74.46.32</p><p>十字星平原</p><p>65.73.47</p><p>66.31.80</p><p>69.31.72</p><p>黄金平原</p><p>63.45.15</p><p>64.38.86</p><p>66.60.90</p><p>埋骨之地</p><p>61.12.46</p><p>62.41.18</p><p>63.83.19</p><p>青铜岩石山</p><p>57.57.65</p><p>59.17.58</p><p>59.32.03</p><p>双冠丘陵</p><p>55.67.03</p><p>57.45.68</p><p>57.59.71</p><p>太初之地</p><p>55.51.34</p><p>57.29.28</p><p>57.43.33</p><p>玛瑞诺普</p><p>53.49.44</p><p>55.45.65</p><p>55.59.16</p><p>白雪森林</p><p>53.45.01</p><p>55.41.03</p><p>55.54.59</p><p>格威尔森林</p><p>53.08.98</p><p>55.46.43</p><p>55.59.92</p><p>黎利尔丘陵</p><p>51.43.84</p><p>53.58.09</p><p>53.71.24</p><p>碎石平原</p><p>51.38.68</p><p>53.52.81</p><p>53.65.84</p><p>十字星平原交易所如下：</p><p>奶酪</p><p>药材</p><p>蜂蜜</p><p>西风脊</p><p>77.49.18</p><p>80.48.02</p><p>80.70.13</p><p>备注：本表基于27.4W 熟练度和130%货率制作，价格随熟练度和货率变动。By：幸运菌</p><p>地狱沼泽</p><p>74.94.48</p><p>78.25.28</p><p>77.55.18</p><p>珊瑚海岸</p><p>74.92.51</p><p>78.23.08</p><p>77.51.79</p><p>埋骨之地</p><p>69.78.48</p><p>71.98.82</p><p>73.06.78</p><p>黄金平原</p><p>67.80.73</p><p>69.58.84</p><p>69.66.42</p><p>格威尔森林</p><p>67.75.75</p><p>67.95.02</p><p>71.58.39</p><p>青铜岩石山</p><p>67.65.63</p><p>67.83.48</p><p>71.41.37</p><p>索兹里德半岛</p><p>65.73.47</p><p>66.31.80</p><p>69.31.72</p><p>黎利尔丘陵</p><p>65.51.48</p><p>66.06.84</p><p>68.94.61</p><p>太初之地</p><p>65.41.34</p><p>65.95.28</p><p>68.77.47</p><p>碎石平原</p><p>63.27.18</p><p>64.18.48</p><p>66.30.76</p><p>白雪森林</p><p>63.16.97</p><p>64.06.93</p><p>66.13.65</p><p>玛瑞诺普</p><p>60.98.83</p><p>62.25.61</p><p>63.60.03</p><p>双冠丘陵</p><p>58.64.20</p><p>60.25.60</p><p>60.78.88</p><p>双冠交易所如下：</p><p>奶酪</p><p>药材</p><p>蜂蜜</p><p>西风脊</p><p>69.16.78</p><p>71.31.73</p><p>72.21.67</p><p>备注：本表基于27.2W 熟练度和130%货率制作，价格随熟练度和货率变动。By：幸运菌</p><p>地狱沼泽</p><p>66.63.15</p><p>69.09.87</p><p>69.08.10</p><p>珊瑚海岸</p><p>66.61.17</p><p>69.07.67</p><p>69.04.65</p><p>埋骨之地</p><p>61.49.29</p><p>62.85.98</p><p>64.61.61</p><p>黄金平原</p><p>58.80.67</p><p>60.47.03</p><p>61.22.62</p><p>十字星平原</p><p>58.39.47</p><p>60.00.18</p><p>60.53.24</p><p>格威尔森林</p><p>57.25.03</p><p>58.84.00</p><p>58.98.37</p><p>青铜岩石山</p><p>57.14.03</p><p>58.72.53</p><p>58.86.78</p><p>索兹里德半岛</p><p>55.43.48</p><p>57.21.44</p><p>57.35.40</p><p>黎利尔丘陵</p><p>55.19.57</p><p>56.96.47</p><p>57.10.37</p><p>太初之地</p><p>55.08.59</p><p>56.84.96</p><p>56.98.86</p><p>碎石平原</p><p>53.14.15</p><p>55.09.04</p><p>55.22.50</p><p>白雪森林</p><p>53.03.09</p><p>54.97.50</p><p>55.10.93</p><p>玛瑞诺普</p><p>51.04.26</p><p>53.16.89</p><p>53.29.85</p><h2 id="_1-2-13-东西大陆发酵野敲点" tabindex="-1">1.2.13 东西大陆发酵野敲点 <a id="s042-f1510e08"></a> <a class="header-anchor" href="#_1-2-13-东西大陆发酵野敲点" aria-label="Permalink to &quot;1.2.13 东西大陆发酵野敲点 &lt;a id=&quot;s042-f1510e08&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>注意！！！野敲每天只能敲100 个货，数量包括你野种的树和种子之类的，一共只</p><p>能100 个！</p><h3 id="西大陆-1" tabindex="-1">西大陆 <a id="s043-75480d7f"></a> <a class="header-anchor" href="#西大陆-1" aria-label="Permalink to &quot;西大陆 &lt;a id=&quot;s043-75480d7f&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>待更新</p><h3 id="东大陆-1" tabindex="-1">东大陆 <a id="s044-b603cf73"></a> <a class="header-anchor" href="#东大陆-1" aria-label="Permalink to &quot;东大陆 &lt;a id=&quot;s044-b603cf73&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>待更新</p><h2 id="_1-2-14-海底宝箱与洛瓦塔沉船-吃探险熟练度" tabindex="-1">1.2.14 海底宝箱与洛瓦塔沉船（吃探险熟练度） <a id="s045-b6d1192b"></a> <a class="header-anchor" href="#_1-2-14-海底宝箱与洛瓦塔沉船-吃探险熟练度" aria-label="Permalink to &quot;1.2.14 海底宝箱与洛瓦塔沉船（吃探险熟练度） &lt;a id=&quot;s045-b6d1192b&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="事前准备" tabindex="-1">事前准备 <a id="s046-62d8596e"></a> <a class="header-anchor" href="#事前准备" aria-label="Permalink to &quot;事前准备 &lt;a id=&quot;s046-62d8596e&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>不管是打捞宝箱还是沉船，开始前都需要准备打捞袋。</p><p>制作方式如下：</p><p>左边的制作工具可以在任意地图的杂货商人处买到。</p><p>如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_806.jpeg" alt="图示：事前准备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_807.jpeg" alt="图示：事前准备" loading="lazy"></figure><h3 id="打捞宝箱" tabindex="-1">打捞宝箱 <a id="s047-22171481"></a> <a class="header-anchor" href="#打捞宝箱" aria-label="Permalink to &quot;打捞宝箱 &lt;a id=&quot;s047-22171481&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>准备好呼吸耳环和脚蹼，最好再准备一个水里用的坐骑，在海底找到宝箱后就可</p><p>海底宝箱如下：</p><p>按F 后，会出现套着打捞袋的宝箱，你可以疾跑到打捞袋上让它带着你一起浮上去。宝箱会固定上浮一定高度，如果到了海面后记得赶紧下来，不然小心被卡住。但是海底深处的宝箱不一定能浮到海面。</p><p>宝箱上浮到最高处后会不动一会，然后刷新建模，这时候就可以交互宝箱来获得物品了。</p><p>从海底摸箱子开始就会有120S 不能继续打捞的DEBUFF，所以靠的比较近的箱子，在你上去再下来后，大概率还需要再等一会。</p><p>打捞海底宝箱大概率会给下面这个：</p><p>此外还有概率给一些卖NPC 的考古小垃圾，以及洛瓦塔潜水艇图纸碎片（绑定的）。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_814.jpeg" alt="图示：打捞宝箱" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_820.jpeg" alt="图示：打捞宝箱" loading="lazy"></figure><h3 id="打捞沉船" tabindex="-1">打捞沉船 <a id="s048-86534c79"></a> <a class="header-anchor" href="#打捞沉船" aria-label="Permalink to &quot;打捞沉船 &lt;a id=&quot;s048-86534c79&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>开始打捞沉船前你需要准备以下道具：</p><p>1 大量打捞袋</p><p>2 带齐装备的潜水艇</p><p>3 带瞭望的船</p><p>4 用于装货的带鱼叉的贸易船</p><p>准备好上述东西后就可以前往寂静之海找沉船了。</p><p>首先我们需要用瞭望在海上找到救生艇，如下图：</p><p>标记渡船前往后可以看到：</p><p>看到渡船后选中渡船，垂直下潜，沉船会刷新在渡船半径200m 的范围内。</p><p>沉船的特征是冒光的海底。如下:</p><p>找到冒光的海底后，掏出你的潜水艇，并换上探测器，使用潜艇1 技能，如下：</p><p>按下技能后海底会冒泡并把你推下潜水艇，动画结束后海底会出现残骸，如下：</p><p>看到残骸后，给潜水艇换上空气炮，让潜水艇头对准残骸，使用潜水艇的空气炮</p><p>技能，如下：</p><p>每次开炮都有概率将你推下坐骑，一般开3-5 炮就会出现沉船，如下：</p><p>靠近沉船按F 交互（消耗打捞袋总数是随机的），交互一次消耗一个打捞袋，交互几次就会出现动画，出现3 次动画后就会出现一个斧头图标的交互键，按下交互键后，沉船就会浮起，并在全寂静之海通报有人挖起了沉船，如下：</p><p>砍完沉船后可以直接站在沉船上一起浮起来，过几秒就可以开始开箱了，不必等</p><p>完全浮起再开箱子。如下：</p><p>每个沉船箱子里有2 包货，普通货箱无熟练度要求，发光货物（蓝框）需要一定探险熟练度才能打开，总数都是16 包货不变。如下：</p><p>等沉船完全浮起来后一般你也开完箱子了，这时候就可以叫出你的贸易船，然后用鱼叉把你的贸易船和沉船贴在一起，这样子方便运货。</p><p>装好货后，就可以去找遗物商人了，遗物商人在光芒、双冠、黎明和自由岛都有，</p><p>如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_821.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_827.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_828.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_833.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_834.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_839.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_840.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_845.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_846.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_851.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_852.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_857.jpeg" alt="图示：打捞沉船" loading="lazy"></figure><h3 id="资源点位-转载" tabindex="-1">资源点位（转载） <a id="s049-9829f3be"></a> <a class="header-anchor" href="#资源点位-转载" aria-label="Permalink to &quot;资源点位（转载） &lt;a id=&quot;s049-9829f3be&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_862.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_863.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_869.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_870.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_875.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_876.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_881.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_882.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_887.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_888.jpeg" alt="图示：资源点位（转载）" loading="lazy"></figure><h2 id="_1-2-15-领地走私货品-不推荐" tabindex="-1">1.2.15 领地走私货品（不推荐） <a id="s050-f7b6c81a"></a> <a class="header-anchor" href="#_1-2-15-领地走私货品-不推荐" aria-label="Permalink to &quot;1.2.15 领地走私货品（不推荐） &lt;a id=&quot;s050-f7b6c81a&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="开启每日流程" tabindex="-1">开启每日流程 <a id="s051-f641750a"></a> <a class="header-anchor" href="#开启每日流程" aria-label="Permalink to &quot;开启每日流程 &lt;a id=&quot;s051-f641750a&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>这个任务第一次时需要玩家在对应领地的庭院植物员处接取任务。</p><p>如下图，红圈为接任务NPC，篮框为任务：</p><p>接到任务后会获得一个传送卷轴，会传送去对应势力的走私NPC 处。</p><p>然后走近头顶冒蓝光的走私NPC 按F 交互即可。</p><p>交互完NPC 会可以交任务，交完介绍任务后，NPC 头顶会出现紫色感叹号。</p><p>以上部分完成后，下次直接从以下步骤开始！！！</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_893.jpeg" alt="图示：开启每日流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_894.jpeg" alt="图示：开启每日流程" loading="lazy"></figure><h3 id="走私品材料获取" tabindex="-1">走私品材料获取 <a id="s052-233ccebc"></a> <a class="header-anchor" href="#走私品材料获取" aria-label="Permalink to &quot;走私品材料获取 &lt;a id=&quot;s052-233ccebc&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>在走私NPC 接取完紫色的任务后，会获得一个每日任务，要求如下：</p><p>拿到花后与走私NPC 对话完成任务，他会再出一个紫色任务让你去领地找庭院植物管理员，这时候还没消耗花，但是背包会多出来一个任务道具。</p><p>到对应势力领地的热情的庭院植物员交任务后，会消耗3 色庭院花各5 朵和任务道具交任务，然后同NPC 处接取以下任务：</p><p>是的，你没看错，这坑爹玩意还要你提交3 个领地币才能拿到制作原料的加工过的庭院植物。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_902.jpeg" alt="图示：走私品材料获取" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_908.jpeg" alt="图示：走私品材料获取" loading="lazy"></figure><h3 id="走私品的制备" tabindex="-1">走私品的制备 <a id="s053-eae743f4"></a> <a class="header-anchor" href="#走私品的制备" aria-label="Permalink to &quot;走私品的制备 &lt;a id=&quot;s053-eae743f4&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>拿到加工过的庭院植物后，玩家可以在对应领地的庭院植物管理员处接到指引做</p><p>货任务：</p><p>拿到加工过的庭院植物后，玩家可以在对应领地的势力总部的小帐篷里用矿泉水或者火木启动制作台（地图能获得哪个就需要那个）（注意！！！做的时候也吃熟练度）</p><p>如下图，红框为制作点，篮圈里的木箱为制作台：</p><p>走到篮圈交互即会出现下图制作台：</p><p>注意！！！交互完之后，不会有什么动画和动作，但是你背的东西实际上以及变成</p><p>走私品了。如下图：</p><p>做好货后，需要运到自由岛的黑暗商人处卖，吃熟练度加成和货率（也就是囤多材料后一起做吃货率更亏）。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_909.jpeg" alt="图示：走私品的制备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_915.jpeg" alt="图示：走私品的制备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_916.jpeg" alt="图示：走私品的制备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_917.jpeg" alt="图示：走私品的制备" loading="lazy"></figure><h3 id="走私品的收益" tabindex="-1">走私品的收益 <a id="s054-0c9caa4e"></a> <a class="header-anchor" href="#走私品的收益" aria-label="Permalink to &quot;走私品的收益 &lt;a id=&quot;s054-0c9caa4e&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>满熟练度加成如下：</p><p>安息之地：</p><p>地灵之界：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_922.jpeg" alt="图示：走私品的收益" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_928.jpeg" alt="图示：走私品的收益" loading="lazy"></figure>',463)])])}const h=s(u,[["render",g]]);export{c as __pageData,h as default};
